qry:select.qry:xquery:
				for $r in sql('
SELECT 
	LIQ19_LIQUIDACION.c_liquidacion
	, LIQ19_LIQUIDACION.o_liquidacion
	, LIQ19_LIQUIDACION.d_titulo
FROM 
	LIQ19_LIQUIDACION
WHERE
	LIQ19_LIQUIDACION.e_periodo = {#PARAMIN:@e_periodo}
	AND LIQ19_LIQUIDACION.oi_empresa = {#PARAMIN:@oi_empresa}
	{%? (#PARAMIN:@l_simulacion!='') {% AND LIQ19_LIQUIDACION.l_simulacion = {#PARAMIN:@l_simulacion} %} {% %} %}
	{%? (#PARAMIN:@oi_liquidacion!='') {% AND LIQ19_LIQUIDACION.oi_liquidacion = {#PARAMIN:@oi_liquidacion} %} {% %} %}
			')/ROWS/ROW

for $r in sql(' SELECT LIQ96_CONCEPTOS.c_concepto , max(LIQ96_CONCEPTOS.d_concepto) as d_concepto , LIQ12_TIPOS_CONC.e_orden FROM LIQ99_LIQUIDACION AS LF , LIQ20_CONC_LIQ_PER , LIQ19_EJECUCIONES , LIQ19_LIQUIDACION , LIQ96_CONCEPTOS , LIQ12_TIPOS_CONC , LIQ99_RECIBOS AS R , LIQ20_TOT_LIQ_PER AS TLP JOIN LF.oi_liquidacion_ddo INNER LIQ19_EJECUCIONES.oi_liquidacion_ddo , LIQ19_LIQUIDACION.oi_liquidacion INNER LIQ19_EJECUCIONES.oi_liquidacion , LF.oi_liquidacion_ddo INNER R.oi_liquidacion_ddo , R.oi_tot_liq_per INNER TLP.oi_tot_liq_per , LIQ96_CONCEPTOS.c_tipo_concepto INNER LIQ12_TIPOS_CONC.c_tipo_concepto , TLP.oi_tot_liq_per INNER LIQ20_CONC_LIQ_PER.oi_tot_liq_per , LIQ20_CONC_LIQ_PER.oi_concepto_ddo INNER LIQ96_CONCEPTOS.oi_concepto_ddo WHERE LF.c_estado = \'F\' AND LIQ19_LIQUIDACION.oi_empresa = {#PARAMIN:@oi_empresa} AND LIQ19_LIQUIDACION.e_periodo = {#PARAMIN:@e_periodo} AND LIQ12_TIPOS_CONC.l_nolistado = 0 {%? (#PARAMIN:@oi_liquidacion!='') {% AND LIQ19_LIQUIDACION.oi_liquidacion = {#PARAMIN:@oi_liquidacion} %} {% %} %} {%? (#PARAMIN:@oi_tipo_concepto!='') {% AND LIQ12_TIPOS_CONC.oi_tipo_concepto = {#PARAMIN:@oi_tipo_concepto} %} {% %} %} {%? (string(#PARAMIN:ROWS/ROW/@id)!='') {% AND LIQ96_CONCEPTOS.c_concepto in (Select L.c_concepto from LIQ14_CONCEPTOS as L where L.oi_concepto in ({%=string(#PARAMIN:ROWS/ROW/@id) %})) %} {% %} %} GROUP BY LIQ12_TIPOS_CONC.e_orden , LIQ96_CONCEPTOS.c_concepto
{%? (string(#PARAMIN:@l_mostrarTodos)='1') {% UNION SELECT L14b.c_concepto , L14b.d_concepto , L12b.e_orden FROM LIQ14_CONCEPTOS as L14b , LIQ12_TIPOS_CONC as L12b where L14b.oi_tipo_concepto = L12b.oi_tipo_concepto AND L12b.l_nolistado = 0 AND L14b.l_activo = 1 {%? (#PARAMIN:@oi_tipo_concepto!='') {% AND L12b.oi_tipo_concepto = {#PARAMIN:@oi_tipo_concepto} %} {% %} %} {%? (string(#PARAMIN:ROWS/ROW/@id)!='') {% AND L14b.oi_concepto in ({%=string(#PARAMIN:ROWS/ROW/@id) %}) %} {% %} %} %} {% %} %}
ORDER BY e_orden ASC, c_concepto ASC')/ROWS/ROW

for $r in sql(' SELECT LIQ96_CONCEPTOS.c_concepto , max(LIQ96_CONCEPTOS.d_concepto) as d_concepto , LIQ12_TIPOS_CONC.e_orden FROM LIQ99_LIQUIDACION AS LF , LIQ19_LIQUIDACION , LIQ20_CONC_LIQ_PER , LIQ19_EJECUCIONES , LIQ96_CONCEPTOS , LIQ12_TIPOS_CONC , LIQ99_RECIBOS AS R , LIQ20_TOT_LIQ_PER AS TLP JOIN LF.oi_liquidacion_ddo INNER LIQ19_EJECUCIONES.oi_liquidacion_ddo , LIQ19_LIQUIDACION.oi_liquidacion INNER LIQ19_EJECUCIONES.oi_liquidacion , LF.oi_liquidacion_ddo INNER R.oi_liquidacion_ddo , R.oi_tot_liq_per INNER TLP.oi_tot_liq_per , LIQ96_CONCEPTOS.c_tipo_concepto INNER LIQ12_TIPOS_CONC.c_tipo_concepto , TLP.oi_tot_liq_per INNER LIQ20_CONC_LIQ_PER.oi_tot_liq_per , LIQ20_CONC_LIQ_PER.oi_concepto_ddo INNER LIQ96_CONCEPTOS.oi_concepto_ddo WHERE LF.c_estado = \'F\' AND LIQ19_LIQUIDACION.oi_empresa = {#PARAMIN:@oi_empresa} AND LIQ19_LIQUIDACION.e_periodo = {#PARAMIN:@e_periodo} AND LIQ12_TIPOS_CONC.l_nolistado = 0 {%? (#PARAMIN:@oi_liquidacion!='') {% AND LIQ19_LIQUIDACION.oi_liquidacion = {#PARAMIN:@oi_liquidacion} %} {% %} %} {%? (#PARAMIN:@oi_tipo_concepto!='') {% AND LIQ12_TIPOS_CONC.oi_tipo_concepto = {#PARAMIN:@oi_tipo_concepto} %} {% %} %} {%? (string(#PARAMIN:ROWS/ROW/@id)!='') {% AND LIQ96_CONCEPTOS.c_concepto in (Select L.c_concepto from LIQ14_CONCEPTOS as L where L.oi_concepto in ({%=string(#PARAMIN:ROWS/ROW/@id) %})) %} {% %} %} GROUP BY LIQ12_TIPOS_CONC.e_orden , LIQ96_CONCEPTOS.c_concepto
{%? (string(#PARAMIN:@l_mostrarTodos)='1') {% UNION SELECT L14b.c_concepto , L14b.d_concepto , L12b.e_orden FROM LIQ14_CONCEPTOS as L14b , LIQ12_TIPOS_CONC as L12b where L14b.oi_tipo_concepto = L12b.oi_tipo_concepto AND L12b.l_nolistado = 0 AND L14b.l_activo = 1 {%? (#PARAMIN:@oi_tipo_concepto!='') {% AND L12b.oi_tipo_concepto = {#PARAMIN:@oi_tipo_concepto} %} {% %} %} {%? (string(#PARAMIN:ROWS/ROW/@id)!='') {% AND L14b.oi_concepto in ({%=string(#PARAMIN:ROWS/ROW/@id) %}) %} {% %} %} %} {% %} %}
ORDER BY e_orden ASC, c_concepto ASC ')/ROWS/ROW
